Code
library(leaflet)

sf_2026G &lt;- df_2026 |&gt;
    filter(nom %in% c("MAUGER", "GAILLARD", "WIETZERBIN", "BONAZZI")) |&gt;
    mutate(
        score = voix / exprimes,
        codeBureauVote = glue::glue(
            "{code_insee}_{str_pad(code_bureau_vote, 4, pad = '0')}"
        )
    ) |&gt;
    left_join(
        sig9213 |&gt; select(codeBureauVote, geometry),
        by = "codeBureauVote"
    ) |&gt;
    sf::st_as_sf()

pal &lt;- colorNumeric(
    palette = "Reds",
    domain = sf_2026G$score,
    na.color = "transparent"
)

leaflet(sf_2026G) |&gt;
    addProviderTiles(providers$CartoDB.Positron) |&gt;
    addPolygons(
        fillColor = ~ pal(score),
        fillOpacity = 0.7,
        weight = 0.3,
        color = "white",
        opacity = 0.8,
        popup = ~ glue::glue(
            "&lt;b&gt;{commune}&lt;/b&gt;&lt;br&gt;{nom} : {scales::percent(score, accuracy = 0.01, decimal.mark = ',')}"
        )
    ) |&gt;
    addControl(
        html = "Score des candidates soutenus par le PS&lt;br&gt;Municipales 2026 • 1er tour • Communes 92-13",
        position = "bottomleft"
    )
